const item = $input.first().json;
const emailText = (item.response || '').split('\\n').join('\n');
const lead = $('Loop Over Items').item.json;

return [{
  json: {
    name: lead.name || '',
    email: lead.email || '',
    company: lead.company || '',
    title: lead.title || '',
    tier: lead.tier || '',
    score: lead.score || 0,
    ai_email: emailText || '',
    variant: "A",
    sent_at: new Date().toISOString()
  }
}];

